div.script:
                        
                        // Odoo API Helper
                        const odooRpc = {
                            call: function(model, method, args, kwargs) {
                                return new Promise((resolve, reject) => {
                                    fetch('/web/dataset/call_kw/' + model + '/' + method, {
                                        method: 'POST',
                                        headers: {
                                            'Content-Type': 'application/json',
                                            'X-CSRF-Token': document.querySelector('[name=csrf_token]')?.value || ''
                                        },
                                        body: JSON.stringify({
                                            jsonrpc: '2.0',
                                            method: 'call',
                                            params: {
                                                model: model,
                                                method: method,
                                                args: args || [],
                                                kwargs: kwargs || {}
                                            },
                                            id: Math.random()
                                        })
                                    })
                                    .then(response => response.json())
                                    .then(data => {
                                        if (data.result) resolve(data.result);
                                        else reject(data.error);
                                    })
                                    .catch(reject);
                                });
                            }
                        };

                        // Fetch receipt from Odoo
                        function fetchReceipt(receiptId) {
                            document.getElementById('loading').style.display = 'block';
                            document.getElementById('content').style.display = 'none';

                            odooRpc.call('sand.billing.receipt', 'search_read', [[['receipt_id', '=', receiptId]]], {})
                                .then(records => {
                                    if (records && records.length > 0) {
                                        displayReceipt(records[0]);
                                        showSuccess('Receipt loaded successfully!');
                                    } else {
                                        showError('Receipt not found. Please check the ID.');
                                    }
                                    document.getElementById('loading').style.display = 'none';
                                    document.getElementById('content').style.display = 'block';
                                })
                                .catch(error => {
                                    console.error('Error:', error);
                                    showError('Failed to load receipt. Please try again.');
                                    document.getElementById('loading').style.display = 'none';
                                    document.getElementById('content').style.display = 'block';
                                });
                        }

                        // Display receipt data
                        function displayReceipt(data) {
                            setText('receiptId', data.receipt_id);
                            setText('orderId', data.order_id);
                            setText('tripNo', data.trip_no);
                            setText('dispatchId', data.dispatch_id);
                            setText('customerName', data.customer_name);
                            setText('customerMobile', data.customer_mobile);
                            setText('constructionName', data.construction_name);
                            setText('sandQuantity', data.sand_quantity ? data.sand_quantity.toFixed(1) + ' MT' : '-');
                            setText('supplyPoint', data.sand_supply_point);
                            setText('dispatchDate', formatDate(data.dispatch_date));
                            setText('registrationDate', formatDate(data.registration_date));
                            setText('driverName', data.driver_name);
                            setText('driverMobile', data.driver_phone);
                            setText('vehicleNo', data.vehicle_no);
                            setText('address', data.address);
                            setText('regAddress', data.registration_address);

                            const statusEl = document.getElementById('status');
                            statusEl.innerText = (data.state || 'draft').toUpperCase();
                            statusEl.className = 'val ' + (data.state === 'confirmed' ? 'status-confirmed' : 'status-draft');
                        }

                        // Helper functions
                        function setText(id, text) {
                            const el = document.getElementById(id);
                            if (el) el.innerText = text || '-';
                        }

                        function formatDate(dateStr) {
                            if (!dateStr) return '-';
                            const date = new Date(dateStr);
                            return date.toLocaleDateString() + ' ' + date.toLocaleTimeString();
                        }

                        function searchReceipt() {
                            const receiptId = document.getElementById('receiptInput').value.trim();
                            if (!receiptId) {
                                showError('Please enter a Receipt ID');
                                return;
                            }
                            fetchReceipt(receiptId);
                        }

                        function clearInput() {
                            document.getElementById('receiptInput').value = '';
                            clearMessages();
                        }

                        function showSuccess(msg) {
                            const el = document.getElementById('successMsg');
                            el.innerText = '✓ ' + msg;
                            el.style.display = 'block';
                            document.getElementById('errorMsg').style.display = 'none';
                            setTimeout(() => el.style.display = 'none', 3000);
                        }

                        function showError(msg) {
                            const el = document.getElementById('errorMsg');
                            el.innerText = '✗ ' + msg;
                            el.style.display = 'block';
                            document.getElementById('successMsg').style.display = 'none';
                        }

                        function clearMessages() {
                            document.getElementById('successMsg').style.display = 'none';
                            document.getElementById('errorMsg').style.display = 'none';
                        }

                        // Allow Enter key to search
                        document.getElementById('receiptInput')?.addEventListener('keypress', function(e) {
                            if (e.key === 'Enter') searchReceipt();
                        });

                        // Initialize - load from URL if available
                        window.addEventListener('DOMContentLoaded', () => {
                            const params = new URLSearchParams(window.location.search);
                            const receiptId = params.get('receipt_id');
                            if (receiptId) {
                                document.getElementById('receiptInput').value = receiptId;
                                searchReceipt();
                            } else {
                                document.getElementById('loading').style.display = 'none';
                                document.getElementById('content').style.display = 'block';
                            }
                        });
